security_findings.evidence:
Unpatched AtapiNoDeviceConnected (sub_1C0001FC8) pseudocode showing missing 0xFF check:

  char AtapiNoDeviceConnected (sub_1c0001fc8)(void* arg1, char* arg2, char arg3, char arg4)
  {
      int64_t rbp;
      rbp = *arg2;              // status byte
      int64_t rdi = 0;          // default: no error

      if (rbp == 0x7f)          // checks 0x7F only
      {
          // retry loop: re-reads status, updates *arg2
          do {
              AtaPortStallExecution(0x1388);
              rax_1 = AtaPortReadPortUchar(*(arg1 + 0x48));
              *arg2 = rax_1;    // status may become 0xFF here!
              if (rax_1 != rbp) break;
              i += 1;
          } while (i < 3);
          // ... NO re-check for 0xFF after loop
      }
      else if (arg3 && !rbp)    // checks 0x00 with arg3
          goto label_1c000200f;

      // 0xFF falls through here → returns 0 (NO ERROR)
      return rdi;
  }

